payload.raw:
{
  "layout": "cards-split",
  "title": "创新设计",
  "subtitle": "",
  "cards": [
    {
      "heading": "仿生柔性传感",
      "body": "采用液态金属-聚氨酯复合薄膜与鱼网拓扑结构，应变系数>150，迟滞<5%，实现0.1mm级空间分辨率。融合光纤传感与IMU的混合架构，为高精度手势捕捉奠定硬件基础。",
      "image": {
        "url": "https://images.unsplash.com/photo-1618477462146-050d2767eac4?auto=format&fit=crop&q=80&w=1400"
      }
    },
    {
      "heading": "高鲁棒手势识别",
      "body": "基于分层CNN-LSTM融合架构与自适应滑动窗口分割，结合噪声抑制模块，实现毫秒级实时推理。在复杂工况下实测识别准确率>98.2%，显著提升抗抖动能力。",
      "image": {
        "url": "https://images.unsplash.com/photo-1557682250-33bd709cbe85?auto=format&fit=crop&q=80&w=1400"
      }
    },
